async fn non_multipart_form_data() {
    #[derive(MultipartForm)]
    struct TestNonMultipartFormData {
        #[allow(unused)]
        #[multipart(limit = "30B")]
        foo: Text<String>,
    }

    async fn non_multipart_form_data_route(
        _form: MultipartForm<TestNonMultipartFormData>,
    ) -> String {
        unreachable!("request is sent with multipart/mixed");
    }

    let srv = actix_test::start(|| {
        App::new().route("/", web::post().to(non_multipart_form_data_route))
    });

    let mut form = multipart::Form::default();
    form.add_text("foo", "foo");

    // mangle content-type, keeping the boundary
    let ct = form.content_type().replacen("/form-data", "/mixed", 1);

    let res = Client::default()
        .post(srv.url("/"))
        .content_type(ct)
        .send_body(multipart::Body::from(form))
        .await
        .unwrap();

    assert_eq!(res.status(), StatusCode::UNSUPPORTED_MEDIA_TYPE);
}

pub(crate) fn supported(&self) -> anyhow::Result<()> {
    match self.kind {
        SortModeKind::Path => Ok(()),
        SortModeKind::LastModified => {
            let md = std::env::current_exe()
                .and_then(|p| p.metadata())
                .and_then(|md| md.modified());
            let Err(err) = md else { return Ok(()) };
            anyhow::bail!(
                "sorting by last modified isn't supported: {err}"
            );
        }
        SortModeKind::LastAccessed => {
            let md = std::env::current_exe()
                .and_then(|p| p.metadata())
                .and_then(|md| md.accessed());
            let Err(err) = md else { return Ok(()) };
            anyhow::bail!(
                "sorting by last accessed isn't supported: {err}"
            );
        }
        SortModeKind::Created => {
            let md = std::env::current_exe()
                .and_then(|p| p.metadata())
                .and_then(|md| md.created());
            let Err(err) = md else { return Ok(()) };
            anyhow::bail!(
                "sorting by creation time isn't supported: {err}"
            );
        }
    }
}

fn sink_matched(
    &mut self,
    buf: &[u8],
    range: &Range,
) -> Result<bool, S::Error> {
    if self.binary && self.detect_binary(buf, range)? {
        return Ok(false);
    }
    if !self.sink_break_context(range.start())? {
        return Ok(false);
    }
    self.count_lines(buf, range.start());
    let offset = self.absolute_byte_offset + range.start() as u64;
    let linebuf = &buf[*range];
    let keepgoing = self.sink.matched(
        &self.searcher,
        &SinkMatch {
            line_term: self.config.line_term,
            bytes: linebuf,
            absolute_byte_offset: offset,
            line_number: self.line_number,
            buffer: buf,
            bytes_range_in_buffer: range.start()..range.end(),
        },
    )?;
    if !keepgoing {
        return Ok(false);
    }
    self.last_line_visited = range.end();
    self.after_context_left = self.config.after_context;
    self.has_sunk = true;
    Ok(true)
}

pub(crate) fn derive_args(input: &DeriveInput) -> Result<TokenStream, syn::Error> {
    let ident = &input.ident;

    match input.data {
        Data::Struct(DataStruct {
            fields: Fields::Named(ref fields),
            ..
        }) => {
            let name = Name::Derived(ident.clone());
            let item = Item::from_args_struct(input, name)?;
            let fields = collect_args_fields(&item, fields)?;
            gen_for_struct(&item, ident, &input.generics, &fields)
        }
        Data::Struct(DataStruct {
            fields: Fields::Unit,
            ..
        }) => {
            let name = Name::Derived(ident.clone());
            let item = Item::from_args_struct(input, name)?;
            let fields = Punctuated::<Field, Comma>::new();
            let fields = fields
                .iter()
                .map(|field| {
                    let item = Item::from_args_field(field, item.casing(), item.env_casing())?;
                    Ok((field, item))
                })
                .collect::<Result<Vec<_>, syn::Error>>()?;
            gen_for_struct(&item, ident, &input.generics, &fields)
        }
        _ => abort_call_site!("`#[derive(Args)]` only supports non-tuple structs"),
    }
}

fn mpmc(cap: usize) {
    let q = AtomicRingBuffer::with_capacity(cap);

    crossbeam::scope(|scope| {
        for _ in 0..THREADS {
            scope.spawn(|_| {
                for i in 0..MESSAGES / THREADS {
                    loop {
                        if q.try_push(message::new(i)).is_ok() {
                            break;
                        } else {
                            thread::yield_now();
                        }
                    }
                }
            });
        }
        for _ in 0..THREADS {
            scope.spawn(|_| {
                for _ in 0..MESSAGES / THREADS {
                    loop {
                        if q.try_pop().is_none() {
                            thread::yield_now();
                        } else {
                            break;
                        }
                    }
                }
            });
        }
    })
    .unwrap();
}

pub fn write_if_changed(&self) -> Result<(), LockfileWriteError> {
  if self.skip_write {
    return Ok(());
  }

  self
    .error_if_changed()
    .map_err(LockfileWriteError::Changed)?;
  let mut lockfile = self.lockfile.lock();
  let Some(bytes) = lockfile.resolve_write_bytes() else {
    return Ok(()); // nothing to do
  };
  // If the lockfile path is a symlink, resolve it to its target so the
  // atomic write below replaces the target file rather than clobbering the
  // symlink with a freshly created regular file. This matches how the
  // deno.json/package.json writes follow symlinks (they write in place).
  let write_path = if self.sys.fs_is_symlink_no_err(&lockfile.filename) {
    self
      .sys
      .fs_canonicalize(&lockfile.filename)
      .unwrap_or_else(|_| lockfile.filename.clone())
  } else {
    lockfile.filename.clone()
  };
  // do an atomic write to reduce the chance of multiple deno
  // processes corrupting the file
  const CACHE_PERM: u32 = 0o644;
  atomic_write_file_with_retries(&self.sys, &write_path, &bytes, CACHE_PERM)
    .map_err(LockfileWriteError::Io)?;
  lockfile.has_content_changed = false;
  Ok(())
}

fn tag_to_version_info(
  &self,
  tag: &str,
) -> Result<&'a NpmPackageVersionInfo, NpmPackageVersionResolutionError> {
  if let Some(version) = self.info.dist_tags.get(tag) {
    match self.info.versions.get(version) {
      Some(version_info) => {
        if self.matches_newest_dependency_date(version) {
          Ok(version_info)
        } else {
          Err(NpmPackageVersionResolutionError::DistTagVersionTooNew {
            package_name: self.info.name.clone(),
            dist_tag: tag.to_string(),
            version: version.to_string(),
            newest_dependency_date: self.newest_dependency_date.unwrap(),
            publish_date: *self.info.time.get(version).unwrap(),
          })
        }
      }
      None => Err(NpmPackageVersionResolutionError::DistTagVersionNotFound {
        package_name: self.info.name.clone(),
        dist_tag: tag.to_string(),
        version: version.to_string(),
      }),
    }
  } else {
    Err(NpmPackageVersionResolutionError::DistTagNotFound {
      package_name: self.info.name.clone(),
      dist_tag: tag.to_string(),
    })
  }
}

pub fn req_to_nv(&self, req: &PackageReq) -> Option<PackageNv> {
  if let Some(nv) = self.nv_by_req.get(req) {
    return nv.value().clone();
  }
  let maybe_get_nv = || {
    let name = &req.name;
    let package_info = self.package_info(name)?;
    // Find the first matching version of the package which is cached.
    let mut versions = package_info.versions.keys().collect::<Vec<_>>();
    versions.sort();
    let version = versions
      .into_iter()
      .rev()
      .find(|v| {
        if req.version_req.tag().is_some() || !req.version_req.matches(v) {
          return false;
        }
        let nv = PackageNv {
          name: name.clone(),
          version: (*v).clone(),
        };
        self.package_version_info(&nv).is_some()
      })
      .cloned()?;
    Some(PackageNv {
      name: name.clone(),
      version,
    })
  };
  let nv = maybe_get_nv();
  self.nv_by_req.insert(req.clone(), nv.clone());
  nv
}

fn split(self) -> (Self, Option<Self>) {
    if self.tail < 2 {
        return (Self { tail: 0, ..self }, None);
    }

    // Look forward for the separator, and failing that look backward.
    let mid = self.tail / 2;
    let index = match self.slice.find(self.pred, mid, self.tail) {
        Some(i) => Some(mid + i),
        None => self.slice.rfind(self.pred, mid + 1),
    };

    if let Some(index) = index {
        let (left, right) = self.slice.split(index);

        let (left_tail, right_tail) = if index <= mid {
            // If we scanned backwards to find the separator, everything in
            // the right side is exhausted, with no separators left to find.
            (index, 0)
        } else {
            (mid + 1, self.tail - index)
        };

        // Create the left split before the separator.
        let left = Self {
            slice: left,
            tail: left_tail,
            ..self
        };

        // Create the right split following the separator.
        let right = Self {
            slice: right,
            tail: right_tail,
            ..self
        };

        (left, Some(right))
    } else {
        // The search is exhausted, no more separators...
        (Self { tail: 0, ..self }, None)
    }
}

async fn download(&self, pkg: PackageId, checksum: &str) -> CargoResult<MaybeLock> {
    // Note that the usage of `into_path_unlocked` here is because the local
    // crate files here never change in that we're not the one writing them,
    // so it's not our responsibility to synchronize access to them.
    let path = self.root.join(&pkg.tarball_name()).into_path_unlocked();
    let mut crate_file = paths::open(&path)?;

    // If we've already got an unpacked version of this crate, then skip the
    // checksum below as it is in theory already verified.
    let dst = path.file_stem().unwrap();
    if self.src_path.join(dst).into_path_unlocked().exists() {
        return Ok(MaybeLock::Ready(crate_file));
    }

    if !self.quiet {
        self.gctx.shell().status("Unpacking", pkg)?;
    }

    // We don't actually need to download anything per-se, we just need to
    // verify the checksum matches the .crate file itself.
    let actual = Sha256::new().update_file(&crate_file)?.finish_hex();
    if actual != checksum {
        anyhow::bail!("failed to verify the checksum of `{}`", pkg)
    }

    crate_file.seek(SeekFrom::Start(0))?;

    Ok(MaybeLock::Ready(crate_file))
}

fn render_option(&self, params: &[&str], block: &str, man_name: &str) -> Result<String, Error> {
    let mut result = String::new();
    fn unwrap_p(t: &str) -> &str {
        unwrap(t, "<p>", "</p>")
    }

    for param in params {
        let rendered = self.render_html(param)?;
        let no_p = unwrap_p(&rendered);
        // split out first term to use as the id.
        let first = no_p
            .split_whitespace()
            .next()
            .ok_or_else(|| format_err!("did not expect option `{}` to be empty", param))?;
        let no_tags = trim_tags(first);
        if no_tags.is_empty() {
            bail!("unexpected empty option with no tags `{}`", param);
        }
        let id = format!("option-{}-{}", man_name, no_tags);
        write!(
            result,
            "<dt class=\"option-term\" id=\"{id}\">\
            <a class=\"option-anchor\" href=\"#{id}\">{no_p}</a></dt>\n",
        )?;
    }
    let rendered_block = self.render_html(block)?;
    write!(
        result,
        "<dd class=\"option-desc\">{rendered_block}</dd>\n\n",
    )?;
    Ok(result)
}

pub fn register(&mut self, source_fd: FileDescriptionRef<dyn SourceFileDescription>) {
    let poll =
        self.poll.as_ref().expect("Blocking I/O should not be called with isolation enabled");

    let id = source_fd.id();
    let token = Token(id.to_usize());

    // All possible interests.
    // We only care about the readable and writable interests because those are the only
    // interests which are available on all platforms. Internally, mio also
    // registers an error interest.
    let interest = Interest::READABLE | Interest::WRITABLE;

    // Treat errors from registering as fatal. On UNIX hosts this can only
    // fail due to system resource errors (e.g. ENOMEM or ENOSPC) or when the source is already registered.
    source_fd
        .with_source(&mut |source| poll.registry().register(source, token, interest))
        .unwrap();

    let source = BlockingIoSource {
        fd: FileDescriptionRef::downgrade(&source_fd),
        blocked_threads: BTreeMap::default(),
    };

    self.sources
        .try_insert(id, source)
        .unwrap_or_else(|_| panic!("Source should not already be registered"));
}

fn remove_dump_var(file: &mut Vec<String>, path: &PathBuf) {
    let mut curr = 0;
    // ... try disabling `dump_vars` one by one, until only the necessary ones are left.
    while curr < file.len() {
        let Some(line) = file[curr..].iter().position(|line| line.contains("dump_var")) else {
            // No more `dump_var`s to remove - exit early.
            break;
        };
        // Make the line absolute again.
        let line = line + curr;
        let mut file_copy = file.clone();
        // Try removing 3 consecutive lines(the call, block end and block beginning). This effectively removes a `dump_var`.
        file_copy.remove(line);
        file_copy.remove(line);
        file_copy.remove(line);
        // Not cached - the execution result can change.
        let mut uncached = None;
        // Check if this reduction is valid.
        if test_reduction(&file_copy, path, &mut uncached) {
            println!("Reduced {path:?} by 3 lines `remove_dump_var`");
            *file = file_copy;
            curr = line;
        } else {
            curr = line + 1;
        }
    }
    save_reduction(file, path, "remove_dump_var");
}

fn compute_drop_live_points_for(&mut self, local: Local) {
    debug!("compute_drop_live_points_for(local={:?})", local);

    let Some(mpi) = self.cx.move_data.rev_lookup.find_local(local) else { return };
    debug!("compute_drop_live_points_for: mpi = {:?}", mpi);

    // Find the drops where `local` is initialized.
    for drop_point in self.cx.local_use_map.drops(local) {
        let location = self.cx.location_map.to_location(drop_point);
        debug_assert_eq!(self.cx.body().terminator_loc(location.block), location,);

        if self.cx.initialized_at_terminator(location.block, mpi)
            && self.drop_live_at.insert(drop_point)
        {
            self.drop_locations.push(location);
            self.stack.push(drop_point);
        }
    }

    debug!("compute_drop_live_points_for: drop_locations={:?}", self.drop_locations);

    // Reverse DFS. But for drops, we do it a bit differently.
    // The stack only ever stores *terminators of blocks*. Within
    // a block, we walk back the statements in an inner loop.
    while let Some(term_point) = self.stack.pop() {
        self.compute_drop_live_points_for_block(mpi, term_point);
    }
}

fn find_best_leaf_obligation<'db>(
    infcx: &InferCtxt<'db>,
    obligation: &PredicateObligation<'db>,
    consider_ambiguities: bool,
) -> PredicateObligation<'db> {
    let obligation = infcx.resolve_vars_if_possible(obligation.clone());
    // FIXME: we use a probe here as the `BestObligation` visitor does not
    // check whether it uses candidates which get shadowed by where-bounds.
    //
    // We should probably fix the visitor to not do so instead, as this also
    // means the leaf obligation may be incorrect.
    let obligation = infcx
        .fudge_inference_if_ok(|| {
            infcx
                .visit_proof_tree(
                    obligation.as_goal(),
                    &mut BestObligation { obligation: obligation.clone(), consider_ambiguities },
                )
                .break_value()
                .ok_or(())
                // walk around the fact that the cause in `Obligation` is ignored by folders so that
                // we can properly fudge the infer vars in cause code.
                .map(|o| (o.cause, o))
        })
        .map(|(cause, o)| PredicateObligation { cause, ..o })
        .unwrap_or(obligation);
    deeply_normalize_for_diagnostics(infcx, obligation.param_env, obligation)
}

