pub fn instantiate_query_response_and_region_obligations<R>(
    &self,
    cause: &ObligationCause,
    param_env: ParamEnv<'db>,
    original_values: &OriginalQueryValues<'db>,
    query_response: &Canonical<'db, QueryResponse<'db, R>>,
) -> InferResult<'db, R>
where
    R: TypeFoldable<DbInterner<'db>>,
{
    let InferOk { value: result_args, obligations } =
        self.query_response_instantiation(cause, param_env, original_values, query_response)?;

    for predicate in &query_response.value.region_constraints.outlives {
        let predicate = instantiate_value(self.interner, &result_args, *predicate);
        self.register_outlives_constraint(predicate);
    }

    for assumption in &query_response.value.region_constraints.assumptions {
        let assumption = instantiate_value(self.interner, &result_args, *assumption);
        self.register_region_assumption(assumption);
    }

    let user_result: R =
        query_response
            .instantiate_projected(self.interner, &result_args, |q_r| q_r.value.clone());

    Ok(InferOk { value: user_result, obligations })
}

fn new_inner<R>(
    size: Size,
    align: Align,
    init: AllocInit,
    params: <Bytes as AllocBytes>::AllocParams,
    fail: impl FnOnce() -> R,
) -> Result<Self, R> {
    // We raise an error if we cannot create the allocation on the host.
    // This results in an error that can happen non-deterministically, since the memory
    // available to the compiler can change between runs. Normally queries are always
    // deterministic. However, we can be non-deterministic here because all uses of const
    // evaluation (including ConstProp!) will make compilation fail (via hard error
    // or OOM) upon encountering a `MemoryExhausted` error.
    let bytes = Bytes::zeroed(size, align, params).ok_or_else(fail)?;

    Ok(Allocation {
        bytes,
        provenance: ProvenanceMap::new(),
        init_mask: InitMask::new(
            size,
            match init {
                AllocInit::Uninit => false,
                AllocInit::Zero => true,
            },
        ),
        align,
        mutability: Mutability::Mut,
        extra: (),
    })
}

fn normalize_alias_term(
    &mut self,
    alias_term: I::Term,
    has_escaping: HasEscapingBoundVars,
) -> Result<I::Term, NoSolution> {
    let current_universe = self.infcx.universe();
    self.infcx.create_next_universe();

    let (normalized, ambig_goal) = (self.normalize)(alias_term)?;

    // Return ambiguous higher ranked alias as is, if
    //   - it contains escaping vars, and
    //   - the normalized term contains infer vars newly created
    //     in the normalization above.
    // The problem is that they may be resolved to types
    // referencing the temporary placeholders.
    //
    // We can normalize the ambiguous alias again after the binder is instantiated.
    if ambig_goal.is_some() && has_escaping == HasEscapingBoundVars::Yes {
        let mut visitor = MaxUniverse::new(self.infcx);
        normalized.visit_with(&mut visitor);
        let max_universe = visitor.max_universe();
        if current_universe.cannot_name(max_universe) {
            return Ok(alias_term);
        }
    }

    self.stalled_goals.extend(ambig_goal);
    Ok(normalized)
}

pub fn early_report_macro_deprecation(
    lint_buffer: &mut LintBuffer,
    depr: &Deprecation,
    suggestion_span: Span,
    node_id: NodeId,
    path: String,
) {
    if suggestion_span.in_derive_expansion() {
        return;
    }

    let is_in_effect = depr.is_in_effect();
    let suggestion = depr.suggestion;
    let note = depr.note.map(|ident| ident.name);
    let since_kind = deprecated_since_kind(is_in_effect, depr.since);
    lint_buffer.dyn_buffer_lint(
        deprecation_lint(is_in_effect),
        node_id,
        suggestion_span,
        move |dcx, level| {
            let sub = suggestion.map(|suggestion| DeprecationSuggestion {
                span: suggestion_span,
                kind: "macro".to_owned(),
                suggestion,
            });

            Deprecated { sub, kind: "macro".to_owned(), path, note, since_kind }
                .into_diag(dcx, level)
        },
    );
}

fn check_explanation_has_doctest(explanation: &str, err_code: &str) -> (bool, bool, bool, bool) {
    let mut found_code_example = false;
    let mut found_proper_doctest = false;

    let mut emit_ignore_warning = false;
    let mut no_longer_emitted = false;

    for line in explanation.lines() {
        let line = line.trim();

        if line.starts_with("```") {
            found_code_example = true;

            // Check for the `rustdoc` doctest headers.
            if line.contains("compile_fail") && line.contains(err_code) {
                found_proper_doctest = true;
            }

            if line.contains("ignore") {
                emit_ignore_warning = true;
                found_proper_doctest = true;
            }
        } else if line
            .starts_with("#### Note: this error code is no longer emitted by the compiler")
        {
            no_longer_emitted = true;
            found_code_example = true;
            found_proper_doctest = true;
        }
    }

    (found_code_example, found_proper_doctest, emit_ignore_warning, no_longer_emitted)
}

pub fn insert_presorted(
    &mut self,
    // We require `TrustedLen` to ensure that the `splice` below is actually efficient.
    mut elements: impl Iterator<Item = (K, V)> + DoubleEndedIterator + TrustedLen,
) {
    let Some(first) = elements.next() else {
        return;
    };

    let start_index = self.lookup_index_for(&first.0);

    let elements = match start_index {
        Ok(index) => {
            self.data[index] = first; // overwrite first element
            elements.chain(None) // insert the rest below
        }
        Err(index) => {
            let last = elements.next_back();
            if index == self.data.len()
                || last.as_ref().is_none_or(|l| l.0 < self.data[index].0)
            {
                // We can copy the whole range without having to mix with
                // existing elements.
                self.data
                    .splice(index..index, std::iter::once(first).chain(elements).chain(last));
                return;
            }

            self.data.insert(index, first);
            elements.chain(last) // insert the rest below
        }
    };

    // Insert the rest. This is super inefficicent since each insertion copies the entire tail.
    for (k, v) in elements {
        self.insert(k, v);
    }
}

pub(crate) fn concat(self, other: Self) -> Self {
    if self.start == self.accept {
        return other;
    } else if other.start == other.accept {
        return self;
    }

    let start = self.start;
    let accept = other.accept;

    let mut transitions: Map<State, Transitions<R, T>> = self.transitions;

    for (source, transition) in other.transitions {
        let fix_state = |state| if state == other.start { self.accept } else { state };
        let byte_transitions = transition.byte_transitions.map_states(&fix_state);
        let ref_transitions = transition
            .ref_transitions
            .into_iter()
            .map(|(r, state)| (r, fix_state(state)))
            .collect();

        let old = transitions
            .insert(fix_state(source), Transitions { byte_transitions, ref_transitions });
        assert!(old.is_none());
    }

    Self { transitions, start, accept }
}

fn check_join_lines(
    #[rust_analyzer::rust_fixture] ra_fixture_before: &str,
    #[rust_analyzer::rust_fixture] ra_fixture_after: &str,
) {
    let config = JoinLinesConfig {
        join_else_if: true,
        remove_trailing_comma: true,
        unwrap_trivial_blocks: true,
        join_assignments: true,
    };

    let (before_cursor_pos, before) = extract_offset(ra_fixture_before);
    let file = SourceFile::parse(&before, span::Edition::CURRENT).ok().unwrap();

    let range = TextRange::empty(before_cursor_pos);
    let result = join_lines(&config, &file, range);

    let actual = {
        let mut actual = before;
        result.apply(&mut actual);
        actual
    };
    let actual_cursor_pos = result
        .apply_to_offset(before_cursor_pos)
        .expect("cursor position is affected by the edit");
    let actual = add_cursor(&actual, actual_cursor_pos);
    assert_eq_text!(ra_fixture_after, &actual);
}

pub fn instantiate_canonical_state<D, I, T>(
    delegate: &D,
    span: I::Span,
    param_env: I::ParamEnv,
    orig_values: &mut Vec<I::GenericArg>,
    state: inspect::CanonicalState<I, T>,
) -> T
where
    D: SolverDelegate<Interner = I>,
    I: Interner,
    T: TypeFoldable<I>,
{
    // In case any fresh inference variables have been created between `state`
    // and the previous instantiation, extend `orig_values` for it.
    orig_values.extend(
        state.value.var_values.var_values.as_slice()[orig_values.len()..]
            .iter()
            .map(|&arg| delegate.fresh_var_for_kind_with_span(arg, span)),
    );

    let instantiation =
        compute_query_response_instantiation_values(delegate, orig_values, &state, span);

    let inspect::State { var_values, data } = delegate.instantiate_canonical(state, instantiation);

    unify_query_var_values(delegate, param_env, orig_values, var_values, span);
    data
}

pub(crate) fn set_precision<T>() -> FPUControlWord {
    let mut cw = 0_u16;

    // Compute the value for the Precision Control field that is appropriate for `T`.
    let cw_precision = match size_of::<T>() {
        4 => 0x0000, // 32 bits
        8 => 0x0200, // 64 bits
        _ => 0x0300, // default, 80 bits
    };

    // Get the original value of the control word to restore it later, when the
    // `FPUControlWord` structure is dropped
    // SAFETY: the `fnstcw` instruction has been audited to be able to work correctly with
    // any `u16`
    unsafe {
        asm!(
            "fnstcw word ptr [{}]",
            in(reg) &mut cw,
            options(nostack),
        )
    }

    // Set the control word to the desired precision. This is achieved by masking away the old
    // precision (bits 8 and 9, 0x300) and replacing it with the precision flag computed above.
    set_cw((cw & 0xFCFF) | cw_precision);

    FPUControlWord(cw)
}

pub(crate) fn try_select(&mut self) -> Option<Entry> {
    if self.selectors.is_empty() {
        None
    } else {
        let thread_id = current_thread_id();

        self.selectors
            .iter()
            .position(|selector| {
                // Does the entry belong to a different thread?
                selector.cx.thread_id() != thread_id
                    && selector // Try selecting this operation.
                        .cx
                        .try_select(Selected::Operation(selector.oper))
                        .is_ok()
                    && {
                        // Provide the packet.
                        selector.cx.store_packet(selector.packet);
                        // Wake the thread up.
                        selector.cx.unpark();
                        true
                    }
            })
            // Remove the entry from the queue to keep it clean and improve
            // performance.
            .map(|pos| self.selectors.remove(pos))
    }
}

fn copy_to(&mut self, to: &mut (impl Write + ?Sized)) -> Result<u64> {
    let mut len = 0;

    loop {
        // Hack: this relies on `impl Read for BufReader` always calling fill_buf
        // if the buffer is empty, even for empty slices.
        // It can't be called directly here since specialization prevents us
        // from adding I: Read
        match self.read(&mut []) {
            Ok(_) => {}
            Err(e) if e.is_interrupted() => continue,
            Err(e) => return Err(e),
        }
        let buf = self.buffer();
        if self.buffer().len() == 0 {
            return Ok(len);
        }

        // In case the writer side is a BufWriter then its write_all
        // implements an optimization that passes through large
        // buffers to the underlying writer. That code path is #[cold]
        // but we're still avoiding redundant memcopies when doing
        // a copy between buffered inputs and outputs.
        to.write_all(buf)?;
        len += buf.len() as u64;
        self.discard_buffer();
    }
}

pub(crate) fn turn_into_const_value<'tcx>(
    tcx: TyCtxt<'tcx>,
    constant: ConstAlloc<'tcx>,
    key: ty::PseudoCanonicalInput<'tcx, GlobalId<'tcx>>,
) -> ConstValue {
    let cid = key.value;
    let def_id = cid.instance.def.def_id();
    let is_static = tcx.is_static(def_id);
    // This is just accessing an already computed constant, so no need to check alignment here.
    let ecx = mk_eval_cx_to_read_const_val(
        tcx,
        tcx.def_span(key.value.instance.def_id()),
        key.typing_env,
        CanAccessMutGlobal::from(is_static),
    );

    let mplace = ecx.raw_const_to_mplace(constant).expect(
        "can only fail if layout computation failed, \
        which should have given a good error before ever invoking this function",
    );
    assert!(
        !is_static || cid.promoted.is_some(),
        "the `eval_to_const_value_raw` query should not be used for statics, use `eval_to_allocation` instead"
    );

    // Turn this into a proper constant.
    op_to_const(&ecx, &mplace.into(), /* for diagnostics */ false)
}
